import { useState, useEffect } from "react";
import { C, API_URL } from "../shared/constants";
import { Card, Btn, Input, Sel, PageHeader, Toast } from "../shared/ui";
import CapturaFoto from "./CapturaFoto";
import FirmaDigital from "./FirmaDigital";

// ================================================================
// CONSTANTES
// ================================================================
const ESTADO_ORDEN = {
  pendiente:    { color: "#94A3B8", label: "Pendiente",    icon: "o" },
  en_curso:     { color: "#00B4D8", label: "En Curso",     icon: ">" },
  fachada:      { color: "#3B82F6", label: "Fachada",      icon: "-" },
  inspeccion:   { color: "#F59E0B", label: "Inspeccion",   icon: "-" },
  ejecucion:    { color: "#8B5CF6", label: "Ejecucion",    icon: "-" },
  cerrada:      { color: "#06D6A0", label: "Cerrada",      icon: "v" },
  no_ejecutada: { color: "#EF4444", label: "No Ejecutada", icon: "x" },
  cancelado:    { color: "#EF4444", label: "Cancelado",    icon: "?" },
};

// ================================================================
// HELPER: subir foto al backend como base64
// ================================================================
const subirFoto = async (ordenId, tipo, fotoData, metadata) => {
  const b64 = fotoData.base64.includes(",")
    ? fotoData.base64.split(",")[1]
    : fotoData.base64;
  const res = await fetch(`${API_URL}/ordenes/${ordenId}/fotos`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ orden_id: ordenId, tipo, base64: b64, metadata: metadata || {} })
  });
  if (!res.ok) throw new Error("Error subiendo foto");
  return res.json();
};

// ================================================================
// COMPONENTE PRINCIPAL
// ================================================================
const Servicios = ({ onBack, user }) => {

  // vistas y listas
  const [vista, setVista]               = useState("lista");
  const [ordenes, setOrdenes]           = useState([]);
  const [refs, setRefs]                 = useState([]);
  const [personal, setPersonal]         = useState([]);
  const [loading, setLoading]           = useState(false);
  const [toast, setToast]               = useState(null);
  const [filtroEstado, setFiltroEstado] = useState("");

  // orden activa
  const [ordenSel, setOrdenSel]             = useState(null);
  const [pasoServicio, setPasoServicio]     = useState(1);

  // inspeccion
  const [inspeccion, setInspeccion]         = useState([]);
  const [fotosInspeccion, setFotosInspeccion] = useState({});

  // novedades
  const [novedades, setNovedades]           = useState([]);
  const [formNovedad, setFormNovedad]       = useState({ descripcion: "", tipo: "averia", accion: "cambio" });
  const [showNovedad, setShowNovedad]       = useState(false);

  // fotos del flujo
  const [fotoFachada, setFotoFachada]               = useState(null);
  const [fotoEjecucionAntes, setFotoEjecucionAntes] = useState(null);
  const [fotoEjecucionDespues, setFotoEjecucionDespues] = useState(null);
  const [fotoCliente, setFotoCliente]               = useState(null);

  // cierre
  const [firmaCliente, setFirmaCliente]     = useState(null);
  const [subiendoFoto, setSubiendoFoto]     = useState(false);

  // cierre no ejecutado
  const [motivoNoEjecucion, setMotivoNoEjecucion] = useState("");
  const [fotoNoEjecucion, setFotoNoEjecucion]     = useState(null);

  // reporte
  const [fotosOrden, setFotosOrden]         = useState([]);
  const [descargandoPDF, setDescargandoPDF] = useState(false);

  // form nueva orden
  const [formOrden, setFormOrden] = useState({
    referencia_id: "", tecnico_id: "", tipo_servicio: "montaje",
    cliente_nombre: "", cliente_direccion: "", cliente_telefono: "",
    num_factura: "", observaciones: "", fecha_programada: ""
  });

  // ================================================================
  // CARGA DE DATOS
  // ================================================================
  const cargar = async () => {
    setLoading(true);
    try {
      const [o, r, p] = await Promise.all([
        fetch(`${API_URL}/ordenes`).then(x => x.json()),
        fetch(`${API_URL}/referencias?activo=true`).then(x => x.json()),
        fetch(`${API_URL}/personal`).then(x => x.json()),
      ]);
      setOrdenes(Array.isArray(o) ? o : []);
      setRefs(Array.isArray(r) ? r : []);
      setPersonal(Array.isArray(p) ? p : []);
    } catch {}
    setLoading(false);
  };

  useEffect(() => { cargar(); }, []);

  // ================================================================
  // CREAR ORDEN
  // ================================================================
  const crearOrden = async () => {
    if (!formOrden.referencia_id || !formOrden.cliente_nombre || !formOrden.cliente_direccion) {
      setToast({ msg: "Referencia, cliente y direccion son obligatorios", type: "error" }); return;
    }
    try {
      const res = await fetch(
        `${API_URL}/ordenes?creado_por=${encodeURIComponent(user?.nombre || "admin")}`,
        {
          method: "POST", headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            ...formOrden,
            referencia_id: parseInt(formOrden.referencia_id),
            tecnico_id: formOrden.tecnico_id ? parseInt(formOrden.tecnico_id) : null
          })
        }
      );
      if (res.ok) {
        setToast({ msg: "Orden creada exitosamente", type: "success" });
        setTimeout(() => { setVista("lista"); cargar(); }, 1400);
      } else {
        const e = await res.json();
        setToast({ msg: e.detail || "Error", type: "error" });
      }
    } catch { setToast({ msg: "Error de conexion", type: "error" }); }
  };

  // ================================================================
  // ABRIR ORDEN -> decide vista "servicio" o "reporte"
  // ================================================================
  const abrirOrden = async (ord) => {
    setFotoFachada(null); setFotoEjecucionAntes(null); setFotoEjecucionDespues(null);
    setFotoCliente(null); setFirmaCliente(null); setFotosInspeccion({});
    setMotivoNoEjecucion(""); setFotoNoEjecucion(null);
    setInspeccion([]); setNovedades([]); setFotosOrden([]);
    setOrdenSel(ord);

    if (ord.referencia_id) {
      const refData = refs.find(r => r.id === ord.referencia_id);
      if (refData?.piezas) {
        setInspeccion(refData.piezas.map(p => ({
          pieza_id: p.id, nombre_pieza: p.nombre,
          estado: "ok", novedad_descripcion: "", accion_solicitada: "ninguna"
        })));
      }
    }

    try {
      const [fotos, detalle] = await Promise.all([
        fetch(`${API_URL}/ordenes/${ord.id}/fotos`).then(r => r.json()).catch(() => []),
        fetch(`${API_URL}/ordenes/${ord.id}/detalle`).then(r => r.json()).catch(() => ({}))
      ]);
      setFotosOrden(Array.isArray(fotos) ? fotos : []);
      setNovedades(detalle.novedades || []);
    } catch {}

    let paso = 1;
    if      (ord.estado === "pendiente")   paso = 1;
    else if (ord.estado === "en_curso")    paso = 2;
    else if (ord.estado === "fachada")     paso = 2;
    else if (ord.estado === "inspeccion")  paso = 3;
    else if (ord.estado === "ejecucion")   paso = 4;
    else if (ord.estado === "cerrada" || ord.estado === "no_ejecutada") paso = 5;

    setPasoServicio(paso);
    setVista(
      ord.estado === "cerrada" || ord.estado === "no_ejecutada"
        ? "reporte" : "servicio"
    );
  };

  // ================================================================
  // PASO 1 -> 2: iniciar
  // ================================================================
  const iniciarOrden = async () => {
    try {
      let lat = null, lng = null;
      try {
        const pos = await new Promise((res, rej) =>
          navigator.geolocation.getCurrentPosition(res, rej, { timeout: 5000 })
        );
        lat = pos.coords.latitude; lng = pos.coords.longitude;
      } catch {}
      await fetch(
        `${API_URL}/ordenes/${ordenSel.id}/iniciar?lat=${lat || 0}&lng=${lng || 0}`,
        { method: "PATCH" }
      );
      setOrdenSel(o => ({ ...o, estado: "en_curso", lat_inicio: lat, lng_inicio: lng }));
      setPasoServicio(2);
      setToast({ msg: "Orden iniciada - GPS registrado. Captura la foto de fachada.", type: "success" });
    } catch { setToast({ msg: "Error al iniciar", type: "error" }); }
  };

  // ================================================================
  // PASO 2 -> 3: fachada
  // ================================================================
  const avanzarDesdeFachada = async () => {
    if (!fotoFachada) {
      setToast({ msg: "Debes capturar la foto de fachada antes de continuar", type: "error" }); return;
    }
    try {
      setSubiendoFoto(true);
      await subirFoto(ordenSel.id, "fachada", fotoFachada, {});
      setOrdenSel(o => ({ ...o, estado: "fachada" }));
      setPasoServicio(3);
      setToast({ msg: "Foto guardada - Continuando a inspeccion", type: "success" });
    } catch {
      setToast({ msg: "Error al guardar foto de fachada", type: "error" });
    } finally { setSubiendoFoto(false); }
  };

  // ================================================================
  // PASO 3: inspeccion bifurcada
  //   armable=true  -> paso 4 ejecucion
  //   armable=false -> paso 5 cierre no ejecutado
  // ================================================================
  const guardarInspeccion = async (armable = true) => {
    const piezasConProblema = inspeccion.filter(p => p.estado !== "ok");
    const faltanFotos = piezasConProblema.filter(p => !fotosInspeccion[p.pieza_id]);
    if (faltanFotos.length > 0) {
      setToast({ msg: `Faltan fotos en ${faltanFotos.length} pieza(s) con problemas`, type: "error" }); return;
    }
    try {
      await fetch(`${API_URL}/ordenes/${ordenSel.id}/inspeccion`, {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify(inspeccion)
      });
      if (armable) {
        setOrdenSel(o => ({ ...o, estado: "ejecucion" }));
        setPasoServicio(4);
        setToast({ msg: "Inspeccion guardada - Producto armable", type: "success" });
      } else {
        setOrdenSel(o => ({ ...o, estado: "inspeccion" }));
        setPasoServicio(5);
        setToast({ msg: "Producto NO armable - Completa el cierre", type: "warning" });
      }
    } catch { setToast({ msg: "Error al guardar inspeccion", type: "error" }); }
  };

  // ================================================================
  // PASO 4 -> 5: fotos ejecucion
  // ================================================================
  const avanzarDesdeEjecucion = async () => {
    if (!fotoEjecucionAntes || !fotoEjecucionDespues) {
      setToast({ msg: "Debes capturar ambas fotos para continuar", type: "error" }); return;
    }
    try {
      setSubiendoFoto(true);
      await subirFoto(ordenSel.id, "producto_abierto",  fotoEjecucionAntes,   {});
      await subirFoto(ordenSel.id, "producto_cerrado",  fotoEjecucionDespues, {});
      setOrdenSel(o => ({ ...o, estado: "ejecucion" }));
      setPasoServicio(5);
      setToast({ msg: "Fotos guardadas - Continua al cierre", type: "success" });
    } catch {
      setToast({ msg: "Error al guardar fotos", type: "error" });
    } finally { setSubiendoFoto(false); }
  };

  // ================================================================
  // PASO 5A: cierre NO EJECUTADO
  // ================================================================
  const handleFotoNoEjecucion = async (fotoData) => {
    setFotoNoEjecucion(fotoData);
    try {
      setSubiendoFoto(true);
      await subirFoto(ordenSel.id, "no_ejecutada", fotoData, { motivo: motivoNoEjecucion });
      setToast({ msg: "Foto de evidencia guardada", type: "success" });
    } catch {
      setToast({ msg: "Error al guardar foto", type: "error" });
    } finally { setSubiendoFoto(false); }
  };

  const cerrarOrdenNoEjecutada = async () => {
    if (!motivoNoEjecucion.trim()) {
      setToast({ msg: "Debes explicar por que no se pudo ejecutar", type: "error" }); return;
    }
    if (!fotoNoEjecucion) {
      setToast({ msg: "Se requiere foto de evidencia", type: "error" }); return;
    }
    if (!firmaCliente) {
      setToast({ msg: "Se requiere firma del cliente", type: "error" }); return;
    }
    try {
      await fetch(`${API_URL}/novedades_servicio`, {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          orden_id: ordenSel.id, tipo: "no_ejecutada",
          descripcion: motivoNoEjecucion, accion: "informativo"
        })
      });
      await fetch(`${API_URL}/ordenes/${ordenSel.id}/cerrar-no-ejecutada`, { method: "PATCH" });
      setOrdenSel(o => ({ ...o, estado: "no_ejecutada" }));
      setToast({ msg: "Servicio cerrado como NO EJECUTADO", type: "warning" });
      setTimeout(() => { setVista("lista"); cargar(); }, 1600);
    } catch { setToast({ msg: "Error al cerrar", type: "error" }); }
  };

  // ================================================================
  // PASO 5B: cierre EXITOSO
  // ================================================================
  const cerrarOrden = async () => {
    if (!firmaCliente) {
      setToast({ msg: "Se requiere la firma del cliente", type: "error" }); return;
    }
    if (!fotoCliente) {
      setToast({ msg: "Se requiere foto del cliente", type: "error" }); return;
    }
    try {
      setSubiendoFoto(true);
      await subirFoto(ordenSel.id, "cliente", fotoCliente, {});
      await fetch(`${API_URL}/ordenes/${ordenSel.id}/cerrar`, { method: "PATCH" });
      setOrdenSel(o => ({ ...o, estado: "cerrada" }));
      setToast({ msg: "Servicio cerrado exitosamente", type: "success" });
      setTimeout(() => { setVista("lista"); cargar(); }, 1600);
    } catch { setToast({ msg: "Error al cerrar", type: "error" }); }
    finally { setSubiendoFoto(false); }
  };

  // ================================================================
  // DESCARGAR PDF
  // ================================================================
  const descargarPDF = async () => {
    if (!ordenSel) return;
    setDescargandoPDF(true);
    try {
      const res = await fetch(`${API_URL}/ordenes/${ordenSel.id}/reporte-pdf`);
      if (!res.ok) throw new Error("Error");
      const blob = await res.blob();
      const url  = URL.createObjectURL(blob);
      const a    = document.createElement("a");
      a.href = url; a.download = `reporte-${ordenSel.consecutivo}.pdf`;
      a.click(); URL.revokeObjectURL(url);
      setToast({ msg: "PDF descargado", type: "success" });
    } catch { setToast({ msg: "Error al generar PDF", type: "error" }); }
    finally { setDescargandoPDF(false); }
  };

  // ================================================================
  // NOVEDAD MANUAL
  // ================================================================
  const guardarNovedad = async () => {
    if (!formNovedad.descripcion) return;
    try {
      await fetch(`${API_URL}/novedades_servicio`, {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...formNovedad, orden_id: ordenSel.id })
      });
      setNovedades(n => [...n, { ...formNovedad, timestamp: new Date().toISOString() }]);
      setFormNovedad({ descripcion: "", tipo: "averia", accion: "cambio" });
      setShowNovedad(false);
      setToast({ msg: "Novedad registrada", type: "success" });
    } catch {}
  };

  // ================================================================
  // HELPERS RENDER
  // ================================================================
  const ordFiltradas = filtroEstado
    ? ordenes.filter(o => o.estado === filtroEstado)
    : ordenes;

  const refSel = refs.find(r => r.id === parseInt(formOrden.referencia_id));

  const PasosIndicador = ({ paso, noEjecutado }) => {
    const pasos = noEjecutado
      ? ["Inicio", "Inspeccion", "No Ejecutado"]
      : ["Inicio", "Inspeccion", "Ejecucion", "Cierre"];
    return (
      <div style={{ display: "flex", alignItems: "center", gap: 0, marginBottom: 20 }}>
        {pasos.map((p, i) => (
          <div key={i} style={{ display: "flex", alignItems: "center", flex: i < pasos.length - 1 ? 1 : "auto" }}>
            <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 4 }}>
              <div style={{
                width: 32, height: 32, borderRadius: "50%",
                background: paso > i + 1 ? "#06D6A0" : paso === i + 1 ? C.accent : C.bg,
                border: `2px solid ${paso > i + 1 ? "#06D6A0" : paso === i + 1 ? C.accent : C.border}`,
                display: "flex", alignItems: "center", justifyContent: "center",
                fontWeight: 800, fontSize: 12,
                color: paso > i + 1 || paso === i + 1 ? "#fff" : C.muted
              }}>
                {paso > i + 1 ? "v" : i + 1}
              </div>
              <div style={{ fontSize: 9, fontWeight: 700, color: paso === i + 1 ? C.accent : C.muted, whiteSpace: "nowrap" }}>{p}</div>
            </div>
            {i < pasos.length - 1 && (
              <div style={{ flex: 1, height: 2, background: paso > i + 1 ? "#06D6A0" : C.border, margin: "0 4px", marginBottom: 16 }} />
            )}
          </div>
        ))}
      </div>
    );
  };

  // ================================================================
  // VISTA: REPORTE
  // ================================================================
  if (vista === "reporte" && ordenSel) {
    const est = ESTADO_ORDEN[ordenSel.estado] || ESTADO_ORDEN.cerrada;
    const esNoEjecutada = ordenSel.estado === "no_ejecutada";
    const etiquetasFoto = {
      fachada: "Fachada del inmueble", pieza_averiada: "Piezas con problemas",
      producto_abierto: "Producto abierto", producto_cerrado: "Producto cerrado",
      no_ejecutada: "Evidencia no ejecutado"
    };
    return (
      <div>
        {toast && <Toast {...toast} onClose={() => setToast(null)} />}
        <PageHeader
          title={`Reporte ${ordenSel.consecutivo}`}
          subtitle={`${ordenSel.tipo_servicio?.toUpperCase()} - ${ordenSel.referencia_nombre}`}
          onBack={() => { setVista("lista"); cargar(); }}
        />
        <div style={{ maxWidth: 600 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 12, padding: "14px 16px", borderRadius: 10, background: est.color + "15", border: `2px solid ${est.color}40`, marginBottom: 14 }}>
            <div style={{ fontSize: 28 }}>{esNoEjecutada ? "x" : "v"}</div>
            <div>
              <div style={{ fontWeight: 800, color: est.color, fontSize: 15 }}>{est.label}</div>
              <div style={{ fontSize: 12, color: C.muted }}>
                {ordenSel.fecha_cierre ? `Cerrado: ${new Date(ordenSel.fecha_cierre).toLocaleString()}` : ""}
                {ordenSel.duracion_min ? ` | ${Math.floor(ordenSel.duracion_min / 60)}h ${Math.round(ordenSel.duracion_min % 60)}m` : ""}
              </div>
            </div>
          </div>

          <Card style={{ marginBottom: 14 }}>
            <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 10 }}>DATOS DEL SERVICIO</div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
              {[["CLIENTE", ordenSel.cliente_nombre], ["TELEFONO", ordenSel.cliente_telefono || "-"],
                ["REFERENCIA", ordenSel.referencia_nombre], ["TIPO", ordenSel.tipo_servicio],
                ["TECNICO", ordenSel.tecnico_nombre || "-"], ["FACTURA", ordenSel.num_factura || "-"]
              ].map(([k, v]) => (
                <div key={k}>
                  <div style={{ fontSize: 9, color: C.muted }}>{k}</div>
                  <div style={{ fontWeight: 700, fontSize: 12, textTransform: "capitalize" }}>{v}</div>
                </div>
              ))}
              <div style={{ gridColumn: "1 / -1" }}>
                <div style={{ fontSize: 9, color: C.muted }}>DIRECCION</div>
                <div style={{ fontWeight: 700, fontSize: 12 }}>{ordenSel.cliente_direccion}</div>
              </div>
            </div>
          </Card>

          {fotosOrden.length > 0 && (
            <Card style={{ marginBottom: 14 }}>
              <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 12 }}>EVIDENCIA FOTOGRAFICA</div>
              {["fachada", "pieza_averiada", "producto_abierto", "producto_cerrado", "no_ejecutada"].map(tipo => {
                const grupo = fotosOrden.filter(f => f.tipo === tipo);
                if (!grupo.length) return null;
                return (
                  <div key={tipo} style={{ marginBottom: 14 }}>
                    <div style={{ fontSize: 11, fontWeight: 700, color: C.muted, marginBottom: 6 }}>{etiquetasFoto[tipo] || tipo}</div>
                    <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                      {grupo.map((f, idx) => (
                        <img key={idx} src={f.url} alt={tipo}
                          style={{ width: 90, height: 90, objectFit: "cover", borderRadius: 8, border: `1px solid ${C.border}` }} />
                      ))}
                    </div>
                  </div>
                );
              })}
            </Card>
          )}

          {novedades.length > 0 && (
            <Card style={{ marginBottom: 14 }}>
              <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 10 }}>NOVEDADES</div>
              {novedades.map((n, i) => (
                <div key={i} style={{ padding: "10px 12px", marginBottom: 8, borderRadius: 8,
                  background: n.tipo === "no_ejecutada" ? "#EF444410" : n.tipo === "averia" ? "#F59E0B10" : "#00B4D810",
                  border: `1px solid ${n.tipo === "no_ejecutada" ? "#EF444440" : n.tipo === "averia" ? "#F59E0B40" : "#00B4D840"}` }}>
                  <div style={{ fontSize: 11, fontWeight: 700, textTransform: "uppercase", marginBottom: 4,
                    color: n.tipo === "no_ejecutada" ? "#EF4444" : n.tipo === "averia" ? "#F59E0B" : "#00B4D8" }}>{n.tipo}</div>
                  <div style={{ fontSize: 13 }}>{n.descripcion}</div>
                </div>
              ))}
            </Card>
          )}

          <Btn onClick={descargarPDF} disabled={descargandoPDF}
            style={{ width: "100%", padding: 14, background: C.accent, color: "#fff", fontSize: 14, marginBottom: 20 }}>
            {descargandoPDF ? "Generando PDF..." : "DESCARGAR REPORTE PDF"}
          </Btn>
        </div>
      </div>
    );
  }

  // ================================================================
  // VISTA: NUEVA ORDEN
  // ================================================================
  if (vista === "nueva") return (
    <div>
      {toast && <Toast {...toast} onClose={() => setToast(null)} />}
      <PageHeader title="Nueva Orden de Servicio" onBack={() => setVista("lista")} />
      <div style={{ maxWidth: 580 }}>
        <Card style={{ marginBottom: 14 }}>
          <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 12 }}>REFERENCIA Y TIPO</div>
          <Sel label="REFERENCIA *" value={String(formOrden.referencia_id)}
            onChange={v => setFormOrden(f => ({ ...f, referencia_id: v }))}
            options={[{ value: "", label: "Selecciona una referencia..." },
              ...refs.map(r => ({ value: String(r.id), label: `${r.codigo} - ${r.nombre} (${r.categoria})` }))]} />
          {refSel && (
            <div style={{ padding: "10px 12px", background: C.bg, borderRadius: 8, border: `1px solid ${C.border}`, marginTop: 4, marginBottom: 8 }}>
              <div style={{ fontSize: 11, color: C.muted }}>
                {refSel.total_piezas} piezas - Tiempo est. {refSel.tiempo_estimado_min} min - {refSel.marca} {refSel.modelo}
              </div>
            </div>
          )}
          <Sel label="TIPO DE SERVICIO *" value={formOrden.tipo_servicio}
            onChange={v => setFormOrden(f => ({ ...f, tipo_servicio: v }))}
            options={[{ value: "montaje", label: "Montaje" }, { value: "desmontaje", label: "Desmontaje" }, { value: "ambos", label: "Montaje y Desmontaje" }]} />
          <Sel label="TECNICO ASIGNADO" value={String(formOrden.tecnico_id)}
            onChange={v => setFormOrden(f => ({ ...f, tecnico_id: v }))}
            options={[{ value: "", label: "Sin asignar" },
              ...personal.filter(p => p.rol === "tecnico").map(p => ({ value: String(p.id), label: p.nombre }))]} />
          <Input label="FECHA PROGRAMADA" value={formOrden.fecha_programada}
            onChange={v => setFormOrden(f => ({ ...f, fecha_programada: v }))} type="date" />
        </Card>
        <Card style={{ marginBottom: 14 }}>
          <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 12 }}>DATOS DEL CLIENTE</div>
          <Input label="NOMBRE CLIENTE *" value={formOrden.cliente_nombre} onChange={v => setFormOrden(f => ({ ...f, cliente_nombre: v }))} />
          <Input label="DIRECCION *" value={formOrden.cliente_direccion} onChange={v => setFormOrden(f => ({ ...f, cliente_direccion: v }))} placeholder="Calle, barrio, ciudad..." />
          <Input label="TELEFONO" value={formOrden.cliente_telefono} onChange={v => setFormOrden(f => ({ ...f, cliente_telefono: v }))} />
          <Input label="N. FACTURA / PEDIDO" value={formOrden.num_factura} onChange={v => setFormOrden(f => ({ ...f, num_factura: v }))} />
          <div style={{ marginTop: 8 }}>
            <label style={{ fontSize: 11, fontWeight: 600, color: C.muted, display: "block", marginBottom: 4 }}>OBSERVACIONES</label>
            <textarea value={formOrden.observaciones} onChange={e => setFormOrden(f => ({ ...f, observaciones: e.target.value }))}
              placeholder="Instrucciones especiales, acceso, etc..."
              style={{ width: "100%", minHeight: 70, padding: "10px 12px", border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 13, fontFamily: "inherit", resize: "vertical", background: C.bg }} />
          </div>
        </Card>
        <Btn onClick={crearOrden} style={{ width: "100%", padding: 14 }}>CREAR ORDEN DE SERVICIO</Btn>
      </div>
    </div>
  );

  // ================================================================
  // VISTA: FLUJO TECNICO
  // ================================================================
  if (vista === "servicio" && ordenSel) {
    const est = ESTADO_ORDEN[ordenSel.estado] || ESTADO_ORDEN.pendiente;
    const esNoEjecutado = pasoServicio === 5 && ordenSel.estado === "inspeccion";

    return (
      <div>
        {toast && <Toast {...toast} onClose={() => setToast(null)} />}
        <PageHeader
          title={`Orden ${ordenSel.consecutivo}`}
          subtitle={`${ordenSel.tipo_servicio?.toUpperCase()} - ${ordenSel.referencia_nombre}`}
          onBack={() => { setVista("lista"); cargar(); }}
        />
        <div style={{ maxWidth: 600 }}>
          <PasosIndicador paso={pasoServicio} noEjecutado={esNoEjecutado} />

          {/* Info cliente */}
          <Card style={{ marginBottom: 14, borderLeft: `4px solid ${est.color}` }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
              <div>
                <div style={{ fontSize: 11, color: C.muted, fontWeight: 700 }}>CLIENTE</div>
                <div style={{ fontWeight: 800, fontSize: 15 }}>{ordenSel.cliente_nombre}</div>
                <div style={{ fontSize: 12, color: C.muted }}>{ordenSel.cliente_direccion}</div>
                {ordenSel.cliente_telefono && <div style={{ fontSize: 12, color: C.muted }}>{ordenSel.cliente_telefono}</div>}
                {ordenSel.num_factura && <div style={{ fontSize: 11, color: C.accent, fontWeight: 600 }}>Factura: {ordenSel.num_factura}</div>}
              </div>
              <span style={{ padding: "4px 10px", borderRadius: 10, fontSize: 11, fontWeight: 700, color: est.color }}>{est.label}</span>
            </div>
            <div style={{ marginTop: 10, paddingTop: 10, borderTop: `1px solid ${C.border}`, display: "flex", gap: 16 }}>
              <div><div style={{ fontSize: 9, color: C.muted }}>REFERENCIA</div><div style={{ fontSize: 12, fontWeight: 700 }}>{ordenSel.referencia_nombre}</div></div>
              <div><div style={{ fontSize: 9, color: C.muted }}>TIPO</div><div style={{ fontSize: 12, fontWeight: 700, textTransform: "capitalize" }}>{ordenSel.tipo_servicio}</div></div>
              {ordenSel.fecha_inicio && <div><div style={{ fontSize: 9, color: C.muted }}>INICIADO</div><div style={{ fontSize: 12, fontWeight: 700 }}>{new Date(ordenSel.fecha_inicio).toLocaleTimeString()}</div></div>}
            </div>
          </Card>

          {/* PASO 1 */}
          {pasoServicio === 1 && (
            <Card>
              <div style={{ textAlign: "center", padding: "10px 0 16px" }}>
                <div style={{ fontSize: 36, marginBottom: 8 }}>[ GPS ]</div>
                <div style={{ fontWeight: 800, fontSize: 16, marginBottom: 6 }}>Iniciar Orden de Servicio</div>
                <div style={{ fontSize: 13, color: C.muted, marginBottom: 20, lineHeight: 1.5 }}>
                  Al iniciar se registrara tu ubicacion GPS y comenzara el cronometro del servicio.
                </div>
                <Btn onClick={iniciarOrden} style={{ width: "100%", padding: 14, fontSize: 15 }}>
                  INICIAR SERVICIO + GPS
                </Btn>
              </div>
            </Card>
          )}

          {/* PASO 2 */}
          {pasoServicio === 2 && (
            <div>
              <Card style={{ marginBottom: 14 }}>
                <div style={{ textAlign: "center", padding: "10px 0 14px" }}>
                  <div style={{ fontSize: 32, marginBottom: 6 }}>[ FOTO ]</div>
                  <div style={{ fontWeight: 800, fontSize: 16, marginBottom: 6 }}>Documentacion Inicial</div>
                  <div style={{ fontSize: 13, color: C.muted, lineHeight: 1.5 }}>
                    Captura la foto de fachada del inmueble.
                  </div>
                </div>
                <CapturaFoto etiqueta="Foto de Fachada (obligatoria)" obligatoria={true}
                  onFotoCapturada={setFotoFachada} existente={fotoFachada?.base64} disabled={subiendoFoto} />
                {fotoFachada && (
                  <div style={{ padding: "10px 12px", background: "#06D6A010", border: "1px solid #06D6A040", borderRadius: 8, fontSize: 12, color: "#06D6A0", fontWeight: 600, marginTop: 8 }}>
                    v Foto capturada - {(fotoFachada.sizeCompressed / 1024).toFixed(1)} KB
                  </div>
                )}
              </Card>
              <Btn onClick={avanzarDesdeFachada} disabled={!fotoFachada || subiendoFoto}
                style={{ width: "100%", padding: 14, fontSize: 15, opacity: fotoFachada ? 1 : 0.5 }}>
                {subiendoFoto ? "Guardando..." : "CONTINUAR A INSPECCION"}
              </Btn>
            </div>
          )}

          {/* PASO 3 */}
          {pasoServicio === 3 && (
            <Card>
              <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 12 }}>INSPECCION DE PIEZAS</div>
              <div style={{ fontSize: 12, color: C.muted, marginBottom: 14 }}>
                Verifica cada pieza de <strong>{ordenSel.referencia_nombre}</strong>.
              </div>
              {inspeccion.map((p, i) => (
                <div key={i} style={{ padding: "12px 14px", marginBottom: 8, borderRadius: 10,
                  background: p.estado === "ok" ? "#06D6A010" : p.estado === "averiada" ? "#F59E0B10" : "#EF444410",
                  border: `1px solid ${p.estado === "ok" ? "#06D6A040" : p.estado === "averiada" ? "#F59E0B40" : "#EF444440"}` }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 8 }}>
                    <div style={{ width: 28, height: 28, borderRadius: "50%", background: C.accent + "20", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 800, fontSize: 11, color: C.accent, flexShrink: 0 }}>{i + 1}</div>
                    <div style={{ fontWeight: 700, flex: 1 }}>{p.nombre_pieza}</div>
                    <div style={{ display: "flex", gap: 6 }}>
                      {[["ok", "OK", "#06D6A0"], ["averiada", "Averiada", "#F59E0B"], ["faltante", "Faltante", "#EF4444"]].map(([v, l, c]) => (
                        <div key={v} onClick={() => setInspeccion(prev => prev.map((x, idx) => idx === i ? { ...x, estado: v } : x))}
                          style={{ padding: "4px 10px", borderRadius: 20, cursor: "pointer", fontSize: 11, fontWeight: 700,
                            background: p.estado === v ? c + "30" : C.bg, color: p.estado === v ? c : C.muted, border: `1px solid ${p.estado === v ? c : C.border}` }}>{l}</div>
                      ))}
                    </div>
                  </div>
                  {p.estado !== "ok" && (
                    <div>
                      <input value={p.novedad_descripcion}
                        onChange={e => setInspeccion(prev => prev.map((x, idx) => idx === i ? { ...x, novedad_descripcion: e.target.value } : x))}
                        placeholder="Describe el problema..."
                        style={{ width: "100%", padding: "7px 10px", border: `1px solid ${C.border}`, borderRadius: 6, fontSize: 12, marginBottom: 6 }} />
                      <select value={p.accion_solicitada}
                        onChange={e => setInspeccion(prev => prev.map((x, idx) => idx === i ? { ...x, accion_solicitada: e.target.value } : x))}
                        style={{ padding: "7px 10px", border: `1px solid ${C.border}`, borderRadius: 6, fontSize: 12, background: "white", marginBottom: 10, width: "100%" }}>
                        <option value="ninguna">Sin accion requerida</option>
                        <option value="cambio">Solicitar cambio</option>
                        <option value="garantia">Solicitar garantia al proveedor</option>
                      </select>
                      <CapturaFoto etiqueta={`Foto evidencia - ${p.nombre_pieza}`} obligatoria={true}
                        onFotoCapturada={foto => setFotosInspeccion(prev => ({ ...prev, [p.pieza_id]: foto }))}
                        existente={fotosInspeccion[p.pieza_id]?.base64} />
                    </div>
                  )}
                </div>
              ))}
              {inspeccion.length === 0 && (
                <div style={{ textAlign: "center", padding: 20, color: C.muted }}>Esta referencia no tiene piezas registradas</div>
              )}
              <div style={{ display: "flex", gap: 10, marginTop: 14 }}>
                <Btn onClick={() => guardarInspeccion(true)} style={{ flex: 1, padding: 14, background: "#06D6A0", color: "#fff" }}>
                  PRODUCTO ARMABLE
                </Btn>
                <Btn onClick={() => guardarInspeccion(false)} style={{ flex: 1, padding: 14, background: "#EF4444", color: "#fff" }}>
                  NO ARMABLE
                </Btn>
              </div>
            </Card>
          )}

          {/* PASO 4 */}
          {pasoServicio === 4 && (
            <Card>
              <div style={{ textAlign: "center", padding: "8px 0 14px" }}>
                <div style={{ fontSize: 32, marginBottom: 8 }}>[ TRABAJO ]</div>
                <div style={{ fontWeight: 800, fontSize: 16, marginBottom: 6 }}>Trabajo Finalizado</div>
                <div style={{ fontSize: 13, color: C.muted, marginBottom: 16 }}>
                  Documenta el resultado con 2 fotos obligatorias del producto.
                </div>
              </div>
              <CapturaFoto etiqueta="Foto 1: Producto Abierto (cajones/puertas abiertos)" obligatoria={true}
                onFotoCapturada={setFotoEjecucionAntes} existente={fotoEjecucionAntes?.base64} />
              <CapturaFoto etiqueta="Foto 2: Producto Cerrado (todo cerrado)" obligatoria={true}
                onFotoCapturada={setFotoEjecucionDespues} existente={fotoEjecucionDespues?.base64} />
              {fotoEjecucionAntes && fotoEjecucionDespues && (
                <div style={{ padding: "10px 12px", background: "#06D6A010", border: "1px solid #06D6A040", borderRadius: 8, fontSize: 12, color: "#06D6A0", fontWeight: 600, marginBottom: 14 }}>
                  v Ambas fotos capturadas
                </div>
              )}
              <Btn onClick={avanzarDesdeEjecucion}
                disabled={!fotoEjecucionAntes || !fotoEjecucionDespues || subiendoFoto}
                style={{ width: "100%", padding: 14, fontSize: 15, opacity: fotoEjecucionAntes && fotoEjecucionDespues ? 1 : 0.5 }}>
                {subiendoFoto ? "Guardando..." : fotoEjecucionAntes && fotoEjecucionDespues ? "CONTINUAR AL CIERRE" : "Captura ambas fotos para continuar"}
              </Btn>
            </Card>
          )}

          {/* PASO 5A - No ejecutado */}
          {pasoServicio === 5 && ordenSel.estado === "inspeccion" && (
            <Card>
              <div style={{ textAlign: "center", padding: "10px 0 16px" }}>
                <div style={{ fontSize: 32, marginBottom: 8 }}>x</div>
                <div style={{ fontWeight: 800, fontSize: 16, color: "#EF4444", marginBottom: 6 }}>Servicio NO Ejecutado</div>
                <div style={{ fontSize: 13, color: C.muted }}>El producto no se pudo armar. Explica el motivo y adjunta evidencia.</div>
              </div>
              <label style={{ fontSize: 11, fontWeight: 600, color: C.muted, display: "block", marginBottom: 6 }}>MOTIVO (obligatorio)</label>
              <textarea value={motivoNoEjecucion} onChange={e => setMotivoNoEjecucion(e.target.value)}
                placeholder="Explica por que no se pudo ejecutar..."
                style={{ width: "100%", padding: 12, minHeight: 90, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 13, fontFamily: "inherit", resize: "vertical", marginBottom: 14 }} />
              <CapturaFoto etiqueta="Foto de Evidencia (obligatoria)" obligatoria={true}
                onFotoCapturada={handleFotoNoEjecucion} existente={fotoNoEjecucion?.base64} disabled={subiendoFoto} />
              <FirmaDigital onFirmaCapturada={setFirmaCliente} existente={firmaCliente?.base64} />
              <Btn onClick={cerrarOrdenNoEjecutada}
                style={{ width: "100%", padding: 14, background: "#EF4444", color: "#fff", fontSize: 15, marginTop: 10 }}>
                CERRAR COMO NO EJECUTADO
              </Btn>
            </Card>
          )}

          {/* PASO 5B - Cierre exitoso */}
          {pasoServicio === 5 && ordenSel.estado === "ejecucion" && (
            <Card>
              <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 16 }}>CIERRE DEL SERVICIO</div>
              <div style={{ padding: "12px 14px", background: "#06D6A010", borderRadius: 8, border: "1px solid #06D6A040", marginBottom: 14 }}>
                <div style={{ fontSize: 11, color: C.muted, marginBottom: 4 }}>RESUMEN</div>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
                  <div><div style={{ fontSize: 9, color: C.muted }}>CLIENTE</div><div style={{ fontWeight: 700, fontSize: 12 }}>{ordenSel.cliente_nombre}</div></div>
                  <div><div style={{ fontSize: 9, color: C.muted }}>TIPO</div><div style={{ fontWeight: 700, fontSize: 12, textTransform: "capitalize" }}>{ordenSel.tipo_servicio}</div></div>
                  <div><div style={{ fontSize: 9, color: C.muted }}>REFERENCIA</div><div style={{ fontWeight: 700, fontSize: 12 }}>{ordenSel.referencia_nombre}</div></div>
                  <div><div style={{ fontSize: 9, color: C.muted }}>NOVEDADES</div><div style={{ fontWeight: 700, fontSize: 12 }}>{novedades.length}</div></div>
                </div>
              </div>
              <CapturaFoto etiqueta="Foto del Cliente (quien recibe)" obligatoria={true}
                onFotoCapturada={setFotoCliente} existente={fotoCliente?.base64} />
              <FirmaDigital onFirmaCapturada={setFirmaCliente} existente={firmaCliente?.base64} />
              <div style={{ padding: "10px 14px", borderRadius: 8, fontSize: 12, fontWeight: 600, marginBottom: 14,
                background: firmaCliente && fotoCliente ? "#06D6A010" : "#FEF3C7",
                border: `1px solid ${firmaCliente && fotoCliente ? "#06D6A040" : "#F59E0B"}`,
                color: firmaCliente && fotoCliente ? "#06D6A0" : "#92400E" }}>
                {firmaCliente && fotoCliente
                  ? "v Firma y foto del cliente capturadas - Listo para cerrar"
                  : `Pendiente: ${!fotoCliente ? "Foto del cliente" : ""}${!fotoCliente && !firmaCliente ? " + " : ""}${!firmaCliente ? "Firma" : ""}`}
              </div>
              <Btn onClick={cerrarOrden} disabled={!firmaCliente || !fotoCliente || subiendoFoto}
                style={{ width: "100%", padding: 14, fontSize: 15, color: "#fff",
                  background: firmaCliente && fotoCliente ? "#06D6A0" : "#94A3B8",
                  opacity: firmaCliente && fotoCliente ? 1 : 0.6 }}>
                {subiendoFoto ? "Guardando..." : firmaCliente && fotoCliente ? "CERRAR SERVICIO COMPLETADO" : "Completa firma y foto para cerrar"}
              </Btn>
            </Card>
          )}

        </div>
      </div>
    );
  }

  // ================================================================
  // VISTA: LISTA
  // ================================================================
  const kpis = [
    { label: "PENDIENTES", val: ordenes.filter(o => o.estado === "pendiente").length,                                           color: "#94A3B8" },
    { label: "EN CURSO",   val: ordenes.filter(o => ["en_curso","fachada","inspeccion","ejecucion"].includes(o.estado)).length, color: "#F59E0B" },
    { label: "CERRADAS",   val: ordenes.filter(o => o.estado === "cerrada").length,                                             color: "#06D6A0" },
    { label: "NO EJEC.",   val: ordenes.filter(o => o.estado === "no_ejecutada").length,                                        color: "#EF4444" },
  ];

  return (
    <div>
      {toast && <Toast {...toast} onClose={() => setToast(null)} />}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 16 }}>
        <div>
          <h2 style={{ margin: 0, fontSize: 22, fontWeight: 800 }}>Ordenes de Servicio</h2>
          <p style={{ margin: 0, fontSize: 13, color: C.muted }}>{ordFiltradas.length} orden(es)</p>
        </div>
        <Btn onClick={() => {
          setFormOrden({ referencia_id: "", tecnico_id: "", tipo_servicio: "montaje", cliente_nombre: "", cliente_direccion: "", cliente_telefono: "", num_factura: "", observaciones: "", fecha_programada: "" });
          setVista("nueva");
        }}>+ NUEVA ORDEN</Btn>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 10, marginBottom: 16 }}>
        {kpis.map(k => (
          <div key={k.label} style={{ padding: "12px 14px", borderRadius: 10, background: k.color + "10", border: `1px solid ${k.color}30` }}>
            <div style={{ fontSize: 24, fontWeight: 900, color: k.color }}>{k.val}</div>
            <div style={{ fontSize: 10, fontWeight: 700, color: k.color }}>{k.label}</div>
          </div>
        ))}
      </div>

      <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap" }}>
        <div onClick={() => setFiltroEstado("")}
          style={{ padding: "6px 14px", borderRadius: 20, cursor: "pointer", fontSize: 12, fontWeight: 700,
            background: filtroEstado === "" ? C.dark : C.bg, color: filtroEstado === "" ? "#fff" : C.muted,
            border: `1px solid ${filtroEstado === "" ? C.dark : C.border}` }}>Todos</div>
        {Object.entries(ESTADO_ORDEN).map(([k, v]) => (
          <div key={k} onClick={() => setFiltroEstado(k)}
            style={{ padding: "6px 14px", borderRadius: 20, cursor: "pointer", fontSize: 12, fontWeight: 700,
              background: filtroEstado === k ? v.color : C.bg, color: filtroEstado === k ? "#fff" : C.muted,
              border: `1px solid ${filtroEstado === k ? v.color : C.border}` }}>{v.label}</div>
        ))}
      </div>

      {loading ? (
        <div style={{ textAlign: "center", padding: 40, color: C.muted }}>Cargando...</div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {ordFiltradas.map((ord, i) => {
            const est = ESTADO_ORDEN[ord.estado] || ESTADO_ORDEN.pendiente;
            return (
              <Card key={i} onClick={() => abrirOrden(ord)} style={{ cursor: "pointer", borderLeft: `4px solid ${est.color}` }}>
                <div style={{ display: "flex", alignItems: "flex-start", gap: 12 }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                      <span style={{ fontWeight: 900, fontSize: 15 }}>{ord.consecutivo}</span>
                      <span style={{ padding: "2px 8px", borderRadius: 10, fontSize: 10, fontWeight: 700, color: est.color }}>{est.label}</span>
                      <span style={{ padding: "2px 8px", borderRadius: 10, fontSize: 10, background: C.bg, border: `1px solid ${C.border}`, color: C.muted, textTransform: "capitalize" }}>{ord.tipo_servicio}</span>
                    </div>
                    <div style={{ fontWeight: 700, fontSize: 13 }}>{ord.cliente_nombre}</div>
                    <div style={{ fontSize: 12, color: C.muted }}>{ord.cliente_direccion}</div>
                    <div style={{ fontSize: 11, color: C.accent, fontWeight: 600, marginTop: 2 }}>
                      {ord.referencia_nombre}{ord.num_factura ? ` | Fac: ${ord.num_factura}` : ""}
                    </div>
                  </div>
                  <div style={{ textAlign: "right", flexShrink: 0 }}>
                    {ord.tecnico_nombre && <div style={{ fontSize: 11, color: C.muted, marginBottom: 4 }}>{ord.tecnico_nombre}</div>}
                    {ord.duracion_min && <div style={{ fontSize: 11, fontWeight: 700, color: "#06D6A0" }}>{Math.floor(ord.duracion_min / 60)}h {Math.round(ord.duracion_min % 60)}m</div>}
                    <div style={{ fontSize: 10, color: C.muted, marginTop: 4 }}>
                      {ord.fecha_programada || new Date(ord.fecha_creacion).toLocaleDateString()}
                    </div>
                  </div>
                </div>
              </Card>
            );
          })}
          {ordFiltradas.length === 0 && (
            <div style={{ textAlign: "center", padding: 40, color: C.muted }}>
              <div style={{ fontSize: 36, marginBottom: 10 }}>[ OS ]</div>
              <div>No hay ordenes{filtroEstado ? ` en estado "${ESTADO_ORDEN[filtroEstado]?.label}"` : ""}</div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default Servicios;
